1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO claim-office", () => {
5	  // --- Edge case: empty policy ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums for main items (single item, newcomer with first insurance) ---
15	  it.todo("single sword (newcomer, first insurance) → 100 base + 10 first + 5 fee = 115 G");
16	  it.todo("single amulet (newcomer, first insurance) → 60 base + 6 first + 5 fee = 71 → rounds up to 71 G");
17	  it.todo("single staff (newcomer, first insurance) → 80 base + 8 first + 5 fee = 93 G");
18	  it.todo("single potion (newcomer, first insurance) → 40 base + 4 first + 5 fee = 49 G");
19	
20	  // --- Components base premium ---
21	  it.todo("single rune → 25 base + first/fee");
22	  it.todo("2 runes → 50 G base premium (no block)");
23	  it.todo("3 runes → 60 G base premium (block applies)");
24	  it.todo("4 runes → 100 G base premium (no block: requires exactly 3)");
25	  it.todo("7 runes → 175 G base premium (one block of 3 + 4 singles? No — block requires exactly 3; 7 → 7×25 = 175)");
26	
27	  // --- Alike components (clarifying question) ---
28	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
29	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
30	
31	  // --- Premium modifiers in isolation ---
32	  it.todo("cursed sword (newcomer) → 100 + 50 curse + 10 first + 5 fee = 165 G");
33	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
34	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
35	  it.todo("sword cursed AND enchantment 5 → both surcharges apply");
36	  it.todo("customer with exactly 2 years → loyalty discount applies (20%)");
37	  it.todo("customer's second contract → follow-up discount (15%) applies");
38	
39	  // --- Modifier scope on multi-item policies ---
40	  it.todo("policy with cursed sword + plain amulet → base 160, curse 50 (on sword only) = 210 before further modifiers/fee");
41	
42	  // --- Rounding ---
43	  it.todo("premium calculation yielding 197.5 → 198 (rounded up)");
44	  it.todo("payout calculation yielding 350.5 → 350 (rounded down)");
45	
46	  // --- Integration premium examples ---
47	  it.todo("newcomer with cursed sword → 165 G");
48	  it.todo("long-standing (3y) customer, second contract, cursed sword enchantment 7 → 160 G");
49	
50	  // --- Claim processing ---
51	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 - 100 deductible)");
52	  it.todo("rune (insurance 250), damage 200 → payout 100 (200 - 100 deductible)");
53	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (dragon = full, then deductible)");
54	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
55	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
56	  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (high-enchantment then deductible)");
57	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
58	
59	  // --- Cap exhaustion ---
60	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
61	  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
62	  it.todo("policy: sword + 3 runes → insurance sum 1750 (block discount doesn't affect insurance sum)");
63	  it.todo("sword cap 2000; first claim 1500 → payout 1400, remaining cap 600");
64	  it.todo("sword cap 2000; second claim 1500 after first claim → payout 600, remaining cap 0");
65	
66	  // --- Multiple items of same type ---
67	  it.todo("policy with two swords → insurance sum 2000, cap 4000");
68	  it.todo("policy with two swords; both damaged in one claim → each entry treated as separate damage with own deductible");
69	  it.todo("policy with one sword; claim has two sword damages → CLI exits non-zero (rejected)");
70	
71	  // --- Edge cases / errors ---
72	  it.todo("unknown item type in quote (e.g., broomstick) → CLI exits non-zero, error to stderr");
73	  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero");
74	  it.todo("claim contains negative damage amount → CLI exits non-zero");
75	});
